const { simpleParser } = require('mailparser');
const { Parser, DomHandler } = require("htmlparser2");
const { findAll, removeElement } = require("domutils");
const render = require("dom-serializer").default;

var contents = [];
const filtered_messages = $('Model Prompt').all();
for (const item of $input.all()) {
  const mail = await simpleParser(item.json.data);
  const message_data = filtered_messages.find(item => item.json.headers.find(h => h.header.toLowerCase() === 'message-id').data === mail.messageId);
  var message = message_data.json;
  message['content'] = (typeof mail.html === 'string' ? mail.html : mail.textAsHtml) ?? '';
  message['files'] = [];

  // 1. Set up the handler to build the DOM
  const handler = new DomHandler((error, dom) => {
      if (error) {
          console.error(error);
          return;
      }

      // 2. Find all elements with a 'src' attribute
      // Cheerio equivalent: HTML('[src]')
      const elementsWithSrc = findAll(
          (elem) => elem.attribs && elem.attribs.src !== undefined,
          dom
      );

      elementsWithSrc.forEach((elem, i) => {
          const src = elem.attribs.src;

          if (src && src.startsWith('data:')) {
              // Extraction Logic (Identical to your Cheerio code)
              const data_split = src.split(';');

              // Safety check to ensure format is valid data URI
              if (data_split.length > 1) {
                  const mimeType = data_split[0].split(':')[1];
                  const image_extension = mimeType.split('/')[1];
                  const b64_data = data_split[1].split(',')[1];

                  if (['image/gif', 'image/jpeg', 'image/jpg', 'image/png', 'image/webp'].includes(mimeType)) {
                    message['files'].push({
                        name: `EmbeddedImg_${i}.${image_extension}`,
                        type: mimeType,
                        content: b64_data
                    });
                  }

                  // 3. Remove the element from the DOM
                  // Cheerio equivalent: element.remove();
                  removeElement(elem);
              }
          }
      });

      // 4. Update the message content with the modified HTML (Optional)
      // Only needed if you plan to use the HTML after removing the images
      message['content'] = render(dom);
  });

  // 5. Run the parser
  try {
    const parser = new Parser(handler);
    parser.write(message['content']);
    parser.end();
  } catch (error) {
    console.log(`Failed to parse HTML on item ${mail.messageId}\n${error}`);
    console.log(mail);
    continue;
  }

  if (message.attachments) {
    for (const file of mail.attachments) {
      const message_file = message.attachments.find(attachment => attachment.md5 === file.checksum);

      if (!message_file) {
        console.log(`Failed to find file:`);
        console.log(file);
        console.log(`Checked all attached files from PhishER:`);
        console.log(message.attachments);
      }

      if (message_file && ['application/pdf', 'text/html', 'image/png', 'image/jpeg'].includes(message_file.actualContentType) && file.contentType !== 'application/smil') {
        const image = file.contentType.split('/')[0] === 'image';
        if ((image && file.size <= 3750000) || (!image && file.size <= 4000000)) {
          message['files'].push({name: file.filename, type: message_file.actualContentType, content: file.content.toString('base64')});
        }
      }
    }
  }

  const seen = new Set();
  message['files'] = message['files'].filter(file => {
    const isDupe = seen.has(file.content);
    if (!isDupe) {
      seen.add(file.content)
    }

    return !isDupe;
  });

  let patternFiles = message['files']
    .filter(f => /^EmbeddedImg_\d+$/.test(f))
    .sort((a, b) => b.match(/\d+/) - a.match(/\d+/));

  // 2. Remove pattern files (starting from highest) until limit is met OR we run out of matches
  for (let nameToRem of patternFiles) {
      if (message['files'].length <= 5) break;
      message['files'].splice(message['files'].indexOf(nameToRem), 1);
  }

  // 3. Final Truncate: If still over 5, chop from the end
  if (message['files'].length > 5) {
      message['files'].splice(5); 
  }

  var prompt = '';
  prompt += `Email ID: ${message.id}\n`;
  prompt += `Email Subject: ${message.subject}\n`;
  prompt += `Sender: ${message.from}\n`;
  prompt += `Reported By: ${message.reportedBy}\n`;
  prompt += `<KNOWBE4_SCORES>\nClean Confidence: ${ message.phishmlReport ? Math.round(message.phishmlReport.confidenceClean, 2) : 0 }\nSpam Confidence: ${ message.phishmlReport ? Math.round(message.phishmlReport.confidenceSpam, 2) : 0 }\nThreat Confidence: ${ message.phishmlReport ? Math.round(message.phishmlReport.confidenceThreat, 2) : 0 }\n</KNOWBE4_SCORES>\n`;
  prompt += `<HEADERS>\n${message.headers.map(item => `${item.header}: ${item.data}`).join('\n')}\n</HEADERS>\n`;
  prompt += `<ATTACHMENTS>\n${message.attachments?.map(item => item.filename).join('\n') ?? ''}\n</ATTACHMENTS>\n`;
  prompt += `<CONTENT>\n${message.content.replace('CAUTION: Security REMINDER: This is an EXTERNAL EMAIL. Stop and think before RESPONDING or CLICKING a link or OPENING attachments!', '')}\n</CONTENT>`;

  contents.push({ prompt: JSON.stringify(prompt), files: message.files });
}

return contents;

