=mutation {
  phisherCommentCreate(comment: "{{ `My verdict is ${$json.verdict}. ` + $json.analysis.toJsonString().slice(1, -1) }}", id: "{{ $json.id }}") {
    errors {
      field
      placeholders
      reason
      recordId
    }
    node {
      body
      createdAt
    }
  }
}

=mutation {
  phisherTagsCreate(id: "{{ $json.id }}", tags: ["{{ `AI:${$json.verdict.toUpperCase()}` }}"]) {
    errors {
      field
      placeholders
      reason
      recordId
    }
    nodes {
      name
      type
    }
  }
}

=query {
