        sha1
        sha256
        size
        ssdeep
      }
      category
      comments {
        body
        createdAt
      }
      events {
        causer
        createdAt
        eventType
        id
        triggerer
      }
      from
      headers {
        data
        header
        order
      }
      id
      links {
        dispositions
        firstSeen
        id
        lastSeen
        scheme
        target
        url
